#include<bits/stdc++.h>
using namespace std;
int n,m;
const int N=300010,M=600010;
int head[N],nxt[M],to[M],val[M],tot,max1;
void add(int x,int y,int z)
{
    nxt[++tot]=head[x];
    head[x]=tot;
    to[tot]=y;
    val[tot]=z;
}
int rnk[N],s[N],dfncnt,v1[N],lg[N],d[N],f[N][22],dis[N];
struct node
{
    int x,y,lca,d;
}a[N];
void dfs(int x,int fa=0)
{
    dis[x]=dis[fa]+v1[x];
    d[x]=d[fa]+1;
    rnk[++dfncnt]=x;
    f[x][0]=fa;
    for(int i=1;(1<<i)<=d[x];i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(int i=head[x];i;i=nxt[i])
    {
        int v=to[i];
        if(v!=fa)
        {
            v1[v]=val[i];
            dfs(v,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
bool check(int x)
{
    int cnt=0;
    memset(s,0,sizeof(s));
    for(int i=1;i<=m;i++)
    {
        if(a[i].d>x)
        {
            s[a[i].x]++;
            s[a[i].y]++;
            s[a[i].lca]-=2;
            cnt++;
        }
    }
    for(int i=n;i>=1;i--)
    {
        s[f[rnk[i]][0]]+=s[rnk[i]];
        if(v1[rnk[i]]>=max1-x&&s[rnk[i]]>=cnt)
        {
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(int i=1;i<n;i++)
    {
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        add(x,y,z);
        add(y,x,z);
    }
    dfs(1);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&a[i].x,&a[i].y);
        a[i].lca=lca(a[i].x,a[i].y);
        a[i].d=dis[a[i].x]+dis[a[i].y]-dis[a[i].lca]*2;
        max1=max(max1,a[i].d);
    }
    int l=0,r=3e8,best;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
